query:
{
  securityGroups(where: {
    rules_SOME: {
      direction: { eq: "Inbound" },
      action: { eq: "Allow" },
      OR: [
        {sources_INCLUDES: "cidr:0.0.0.0/0"},
        {sources_INCLUDES: "cidr:::/0"},
        {sources_INCLUDES: "tag:Internet"},
        {sources: { eq: [] }}
      ]
    }
  }) {
    ...AssetFragment
  }
}
